<template><div v-if="open" class="w97-modal-overlay"><div class="w97-modal picker"><div class="w97-modal-titlebar">Select {{ titleBase }} <strong>{{ emphasizeText }}</strong></div><div class="w97-modal-body"><input :value="query" @input="emit('update:query',($event.target as HTMLInputElement).value)" @keydown.enter="emit('apply-find')"/><button @click="emit('apply-find')">🔍</button><div class="recipe-scroll"><div v-for="col in recipeCols" :key="col[0]?.id"><div v-for="r in col" :key="r.id" class="list-li" :class="{active:r.id===previewId}" @click="emit('item-click',r.id)" @dblclick="previewRecipe&&emit('select',previewRecipe)">{{ r.name }}</div></div></div><div class="preview">Preview: {{ previewRecipe?.name || 'Select a recipe.' }}</div></div><div class="w97-modal-actions"><button @click="previewRecipe&&emit('select',previewRecipe)">Select</button><button @click="emit('close')">Close</button></div></div></div></template>
<script setup lang="ts">import type { PropType } from 'vue'; import type { RecipeDetail } from '../api/recipeTestApi'; defineProps({open:Boolean,findClass:String,hint:String,query:String,platen:Number,recipeCols:{type:Array as PropType<RecipeDetail[][]>,default:()=>[]},previewId:String,previewRecipe:{type:Object as PropType<RecipeDetail|null>,default:null},titleBase:String,emphasizeText:String,listMode:String,scrollLeft:Number,colWidths:Object}); const emit=defineEmits(['update:query','apply-find','item-click','select','close','register-item-ref','update:listMode','body-scroll','start-resize','register-scroll-el'])</script>
<style scoped>.w97-modal-overlay{position:fixed;inset:0;background:rgba(0,0,0,.35);display:flex;align-items:center;justify-content:center;z-index:10000}.w97-modal{width:min(900px,96vw);background:#c0c0c0;border:2px outset #fff}.w97-modal-titlebar{background:#0a246a;color:#fff;padding:6px 8px;font-weight:900}.w97-modal-body{padding:12px}.recipe-scroll{height:220px;overflow:auto;background:#fff;border:1px solid #8d8d8d;margin-top:8px;padding:8px}.list-li.active{background:#0a246a;color:#fff}.w97-modal-actions{display:flex;justify-content:flex-end;gap:8px;padding:0 12px 12px}</style>
